// Busca productos por nombre/descripcion. Limpia el resultado para evitar alucinaciones.
const axios = require('axios');
const { p_busqueda } = query;
const url = 'https://rgniqjfooifchyctnbzu.supabase.co/rest/v1/rpc/buscar_productos';
const resp = await axios.post(url, { p_busqueda }, {
  headers: { 'apikey': 'REDACTED_SUPABASE_ANON_KEY', 'Authorization': 'Bearer REDACTED_SUPABASE_ANON_KEY', 'Content-Type': 'application/json' }
});
const productos = (resp.data || []).map(p => {
  const stock = Number(p.existencia);
  return {
    codigo: p.codigo_interno,
    nombre: p.descripcion,
    precio_usd: Number(p.precio_venta),
    existencia: stock > 0 ? stock : 0,
    disponible: stock > 0
  };
});
if (productos.length === 0) return 'No se encontraron productos para: ' + p_busqueda;
return JSON.stringify(productos);

