// Obtiene la tasa oficial BCV (Bs por USD).
const axios = require('axios');
const url = 'https://rgniqjfooifchyctnbzu.supabase.co/rest/v1/tazas?nombre=eq.actual&select=bcv_usd';
const resp = await axios.get(url, {
  headers: { 'apikey': 'REDACTED_SUPABASE_ANON_KEY', 'Authorization': 'Bearer REDACTED_SUPABASE_ANON_KEY' }
});
const tasa = resp.data && resp.data[0] && resp.data[0].bcv_usd;
return JSON.stringify({ bcv_usd: tasa });

// Busca en la memoria a largo plazo (Engram).
const axios = require('axios');
const { q } = query;
const url = 'http://host.docker.internal:7437/search?q=' + encodeURIComponent(q) + '&project=whatsapp-agent&scope=project&limit=5';
try {
  const resp = await axios.get(url);
  return JSON.stringify(resp.data);
} catch (e) {
  return JSON.stringify({ resultados: [], nota: 'memoria no disponible' });
}

