// Guarda un dato del cliente/producto en la memoria a largo plazo (Engram).
const axios = require('axios');
const { session_id, type, title, content, topic_key } = query;
try {
  await axios.post('http://host.docker.internal:7437/sessions', { id: session_id, project: 'whatsapp-agent', scope: 'project' });
} catch (e) { /* sesion ya existe */ }
try {
  const resp = await axios.post('http://host.docker.internal:7437/observations', {
    session_id, project: 'whatsapp-agent', scope: 'project', type, title, content, topic_key
  }, { headers: { 'Content-Type': 'application/json' } });
  return JSON.stringify({ guardado: true, id: resp.data && resp.data.id });
} catch (e) {
  return JSON.stringify({ guardado: false, error: String(e.message) });
}

